const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401 } };
return { json: { token, body } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401, error: 'Invalid session' } };
const allowed = ['advisor','sub_agent','mga_principal','admin','supervisor'];
if (allowed.indexOf(row.user_role) === -1) return { json: { _unauthorized: true, status: 403 } };
const b = $('Extract').first().json.body;
const costToday = parseFloat(b.annual_education_cost_cents) || 0;
const yearsToStart = parseFloat(b.years_until_start) || 10;
const yearsAttending = parseFloat(b.years_attending) || 4;
const inflation = parseFloat(b.education_inflation_rate) || 0.05;
const numChildren = parseInt(b.num_children) || 1;
const inflated = costToday * Math.pow(1 + inflation, yearsToStart);
const coverage = Math.round(inflated * yearsAttending * numChildren);
return { json: { ok: true, calculator: 'education', vertical_id: 'insurance', coverage_amount_cents: coverage, inputs: { annual_education_cost_cents: costToday, years_until_start: yearsToStart, years_attending: yearsAttending, education_inflation_rate: inflation, num_children: numChildren }, disclaimer: 'This is an educational estimate only. Final recommendation must be reviewed and approved by a licensed advisor.' } };
